args.sparql:
SELECT ?pm ?pmLabel ?reasonLabel ?endDate WHERE {
  ?pm wdt:P39 wd:Q858 ;
      p:P582 ?statement .
  ?statement ps:P582 ?endDate ;
            pq:P1534 ?reason .
  ?pm rdfs:label ?pmLabel .
  ?reason rdfs:label ?reasonLabel .
  FILTER(LANG(?pmLabel) = "en") .
  FILTER(LANG(?reasonLabel) = "en") .
} ORDER BY DESC(?endDate) LIMIT 4

